              { value: "Office", label: "Office" },
            ]}
          />
          <Select
            value={filterWarehouse}
            onChange={(e) => {
              setFilterWarehouse(e.target.value);
              setCurrentPage(1);
            }}
            options={[
              { value: "", label: "All Warehouses" },
              { value: "WH-001", label: "WH-001" },
              { value: "WH-002", label: "WH-002" },
              { value: "WH-003", label: "WH-003" },
            ]}
          />
          <Select
            value={filterStockStatus}
            onChange={(e) => {
              setFilterStockStatus(e.target.value);
              setCurrentPage(1);
            }}
            options={[
              { value: "", label: "All Status" },
              { value: "In Stock", label: "In Stock" },
              { value: "Low Stock", label: "Low Stock" },
              { value: "Out of Stock", label: "Out of Stock" },
            ]}
          />
        </div>
      </Card>

      {/* Products Table */}
      <Card>
        <Table
          columns={columns}
          data={paginatedProducts}
          emptyMessage="No products found"
        />
        <Pagination
          currentPage={currentPage}
          totalPages={Math.ceil(filteredProducts.length / itemsPerPage)}
          onPageChange={setCurrentPage}
        />
      </Card>

      {/* Product Details Modal */}
      <Modal
        open={showDetails}
        onClose={() => {
          setShowDetails(false);
          setSelectedProduct(null);
        }}
        title={selectedProduct?.name}
        className="w-full max-w-2xl"
      >
        {selectedProduct && (
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium text-gray-600">SKU</label>
                <p className="text-lg font-semibold">{selectedProduct.sku}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-gray-600">Category</label>
                <p className="text-lg font-semibold">{selectedProduct.category}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-gray-600">Quantity</label>
                <p className="text-lg font-semibold">{selectedProduct.quantity}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-gray-600">Warehouse</label>
                <p className="text-lg font-semibold">{selectedProduct.warehouse}</p>
              </div>
            </div>

            {/* Lots/Batches Section */}
            <div>
              <h4 className="font-semibold mb-3">Lot Numbers</h4>
              {selectedProduct.lots.length > 0 ? (
                <div className="space-y-2">
                  {selectedProduct.lots.map((lot, idx) => (
                    <div key={idx} className="border rounded p-3 bg-gray-50">
                      <div className="grid grid-cols-2 gap-2 text-sm">
                        <div><span className="font-medium">Lot:</span> {lot.lot_number}</div>
                        <div><span className="font-medium">Qty:</span> {lot.quantity}</div>
                        <div><span className="font-medium">Expiry:</span> {lot.expiry_date}</div>
                        {lot.serial_numbers.length > 0 && (
                          <div><span className="font-medium">S/N:</span> {lot.serial_numbers.join(", ")}</div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-gray-500 text-sm">No lots available</p>
              )}
            </div>
          </div>
        )}
      </Modal>

      {/* Add Product Modal */}
      <Modal
        open={showAddForm}
        onClose={() => setShowAddForm(false)}
        title="Add Product"
        className="w-full max-w-md"
        footer={
          <>
            <Button variant="secondary" onClick={() => setShowAddForm(false)}>
              Cancel
            </Button>
            <Button onClick={() => setShowAddForm(false)}>
              Save
            </Button>
          </>
        }
      >
        <div className="space-y-4">
          <Input label="Product Name" placeholder="Enter product name" required />
          <Input label="SKU" placeholder="Enter SKU" required />
          <Select
            label="Category"
            options={[
              { value: "Electronics", label: "Electronics" },
              { value: "Accessories", label: "Accessories" },
              { value: "Cables", label: "Cables" },
            ]}
            required
          />
        </div>
      </Modal>
    </div>
  );
};
